sp_angular_provider.script:
/* Use this Directive to add icons for the different types of Comments a Task can have to a table cell with a hover popover function
Note: AngularJS normalizes case-sensitive camelCase to case-insensitive kebab-case for the DOM.
Usage in a widget's HTML:
	<dtech-response-comments dtech-is-modal="data.isModal"
        dtech-reopen-comments="{{item.directive_reopen_comments}}"
        dtech-response-comments="{{item.directive_response_comments}}"
        dtech-reviewer-comments="{{item.directive_reviewer_comments}}"
        dtech-rework-comments="{{item.directive_rework_comments}}"
		dtech-sys-id="{{item.sys_id}}"
		dtech-table="{{data.table}}"
		></dtech-response-comments>

	The HTML for the directive is in	
	templateUrl: getTemplateUrl('x_153465_discovert_dtechResponseComments.html')
//
// Copyrights belong to Discover Technologies LLC. © 2023 Discover Technologies LLC
// Script Continued Below
// 2.8.1 | 2023-04-04 | mmcc | STRY0135723 - Homepage Comments column replaced by Task Comments
//  Created Directive
// 2.8.1 | 2023-04-19 | mmcc | STRY0135713 - Modal showing all comments when clicking the Response Column;
//  Rename directive and change usage of User to Response
//  Updated above Usage in a widget's HTML section to show use of new var names, item.directive_reopen_comments
//  Added dtechSysId, dtechTable and _openModalResponseComments()
// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open
//  Added CONST_POPOVER_DELAY, d._isClosing, d.initTooltip, d.popoverDelay;
//  In function _init(element) added setting d.popoverDelay = CONST_POPOVER_DELAY;
//  Added function _initTooltip(); in function _leaveTooltip() set d._isClosing = true;
//   Added function _popoverDelay(); in function _showDuration(event) set d._isClosing = false;
//
*/
function dtechResponseComments(getTemplateUrl, spModal, $timeout, $window) {
	// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; 400 to 600
	// TODO: get from a service
	var CONST_TEMP_WAIT_DURATION = 600;

	// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; TODO: get from a service
	var CONST_POPOVER_DELAY = 1200;

	var dtResponse = {
		restrict: 'E',
		replace: true,
		// @: string 1 way, =: object 2 way, <: object 1 way
		scope: {
			dtechIsModal: "=",
			dtechReopenComments: '@',
			dtechResponseComments: '@',
			dtechReviewerComments: '@',
			dtechReworkComments: '@',
			dtechSysId: '@',
			dtechTable: '@'
		},
		controller: responseCtrl,
		link: link,
		controllerAs: 'd',
		templateUrl: getTemplateUrl('x_153465_discovert_dtechResponseComments.html')
	};
	return dtResponse;

	function responseCtrl($scope, $attrs, $animate) {
		var d = this;	
		d._isOverTooltip = false;

		// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; added, init to false
		d._isClosing = false;

		d.dtechResponseToolTipOpen = _dtechResponseToolTipOpen;

		// passed in data section
		d.dtechIsModal = _dtechIsModal;
		d.dtechReopenComments = _dtechReopenComments;
		d.dtechResponseComments = _dtechResponseComments;
		d.dtechReviewerComments = _dtechReviewerComments;
		d.dtechReworkComments = _dtechReworkComments;
		d.dtechSysId = _dtechSysId;
		d.dtechTable = _dtechTable;

		// directive's functional section
		d.enterTooltip = _enterTooltip;
		d.init = _init;

		// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; added
		d.initTooltip = _initTooltip;

		d.leaveTooltip = _leaveTooltip;
		d.openModal = _openModal;
		d.openModalResponseComments = _openModalResponseComments;
		d.parentMouseLeave = _parentMouseLeave;

		// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; added to set popover-popup-delay in the HTML
		d.popoverDelay = _popoverDelay;

		d.showResponse = _showResponse;

		function _dtechIsModal() {
			return $scope.dtechIsModal;
		}

		function _dtechReopenComments() {
			return $scope.dtechReopenComments;
		}

		function _dtechResponseComments() {
			return $scope.dtechResponseComments;
		}

		function _dtechReviewerComments() {
			return $scope.dtechReviewerComments;
		}

		function _dtechReworkComments() {
			return $scope.dtechReworkComments;
		}

		function _dtechResponseToolTipOpen(){
			return $scope.dtechResponseToolTipOpen;
		}

		function _dtechSysId() {
			return $scope.dtechSysId;
		}

		function _dtechTable() {
			return $scope.dtechTable;
		}

		// when the user hovers over the tooltip set overtooltip flag
		function _enterTooltip() {
			d._isOverTooltip = true;
		}

		// init()
		// initialize the control, called from the Link function
		// gets a reference to the element
		function _init(element) {

			d.$element = element;

			$scope.dtechResponseToolTipOpen = 
				angular.isDefined($attrs.enterTooltip) ?
				$scope.$parent.$eval($attrs.dtechResponseToolTipOpen) : false;

			// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; set to const
			d.popoverDelay = CONST_POPOVER_DELAY;
		}

		// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; added function
		function _initTooltip() {
			// if the user moved off of the parent before the tooltip opened, cancel the open
			if (d._isClosing == true) {
				_leaveTooltip();
				// d._isClosing = false;
			}
		}

		function _leaveTooltip() {
			d._isOverTooltip = false;
			$scope.dtechResponseToolTipOpen = false;

			// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; set true
			d._isClosing = true;
		}

		// openModal()
		// this function is called from Template html
		// it is called when a user clicks on the open link
		function _openModal(event) {
			_openModalResponseComments(event);

		}

		function _openModalResponseComments(event) {
			var title = '';
			var widget = 'tasker_modal_response_comments';
			spModal.open({
				title: title,
				backdrop: 'static',
				widget: widget,
				widgetInput: {
					isModal: _dtechIsModal(),
					sys_id: _dtechSysId(),
					table:  _dtechTable()
				},
				size: 'lg',
				buttons: [],
				headerStyle: {
					'border-bottom': 'none',
					'padding': '20px 15px 0 20px'
				},
				footerStyle: {
					'display': 'none'
				}
			});

			// modal is openened stop the row or cell click form raising
			event.stopPropagation();

			_leaveTooltip();
		}

		// _parentMouseLeave
		// this is the get function for the direcitve property parentMouseLeave
		// this function is called when the user hovers off the profile image
		function _parentMouseLeave() {
			$timeout(function() {
				if(!d._isOverTooltip){
					d.leaveTooltip();
				}
			}, CONST_TEMP_WAIT_DURATION);
		}

		// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; added function
		function _popoverDelay() {
			return d.popoverDelay;
		}

		function _showResponse(event) {
			$scope.dtechResponseToolTipOpen = true;

			// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; set false
			d._isClosing = false;
		}

	} // end function responseCtrl

	// Link function links local methods to parent controller methods
	// see the list of events being monitored
	function link(scope, element, attrs, responseCtrl) {
		// initialize the control
		responseCtrl.init(element);			
		scope.$on('$destroy',_destroy);

		function _destroy() {
			element.remove();
		}
	}

}
